	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile script: %w", err)
	}

	var result []map[string]interface{}

	for _, item := range items {
		// Inject the current item as a global variable named 'item'
		// Note: otto handles map[string]interface{} by converting it to a JS object.
		err := vm.Set("item", item)
		if err != nil {
