	// Creating a VM for every item is computationally expensive and leads to resource exhaustion.
	vm := otto.New()

	// Optimization: Compile the script once. 
	// This validates syntax before processing data and improves execution performance.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("invalid script syntax: %v", err)
	}

	// Security: Define a strict timeout for script execution.
	// This prevents Denial of Service (DoS) attacks via infinite loops (e.g., "while(true){}")
	// or computationally heavy operations.
	const executionTimeout = 100 * time.Millisecond

