// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Pre-compile the script.
	// This improves performance by avoiding re-parsing for every item and
	// catches syntax errors before processing any data.
	// We use a temporary VM just for compilation.
	tempVM := otto.New()
	script, err := tempVM.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("invalid script syntax: %w", err)
	}

	var result []map[string]interface{}

	for _, item := range items {
		// Create a new VM for each item to ensure complete isolation.
		// This guarantees that variables defined in the script for one item
		// do not leak into the scope of the next item.
		vm := otto.New()

		// Initialize the Interrupt channel. Otto checks this channel during execution.
		// A buffered channel of 1 is sufficient.
		vm.Interrupt = make(chan func(), 1)

		// Inject the current item as a global variable named 'item'
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Run the condition script with a timeout safeguard
		value, err := runWithTimeout(vm, script)
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// runWithTimeout executes the compiled script on the provided VM.
// It sets a timer to interrupt the VM if execution takes too long.
func runWithTimeout(vm *otto.Otto, script *otto.Script) (val otto.Value, err error) {
	// Setup a timer to trigger the interrupt
	timer := time.AfterFunc(executionTimeout, func() {
		// Send a function to the interrupt channel.
		// Otto will execute this function, which panics to halt the VM.
		vm.Interrupt <- func() {
			panic(errTimeout)
		}
	})
