// FilterItems filters a slice of maps based on a JavaScript condition.
// It creates an Otto VM, iterates through the items, injects the current item
// as a global variable 'item', and evaluates the script.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Initialize the JavaScript VM
	vm := otto.New()

	// Optimization: Compile the script once before iterating.
	// This avoids parsing the JavaScript string for every item in the slice.
	program, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}

	// Initialize the result slice
	filteredItems := make([]map[string]interface{}, 0)

	for i, item := range items {
		// Inject the current item into the JS environment as the variable 'item'
		// Otto automatically handles the conversion of map[string]interface{} to a JS Object.
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set 'item' variable at index %d: %w", i, err)
		}

		// Execute the pre-compiled script
		val, err := vm.Run(program)
		if err != nil {
			return nil, fmt.Errorf("script execution failed at index %d: %w", i, err)
		}

		// Convert the result to a boolean
		// Otto follows JavaScript truthy/falsy rules here.
		keep, err := val.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean at index %d: %w", i, err)
		}

		// If true, append to results
		if keep {
			filteredItems = append(filteredItems, item)
		}
	}

	return filteredItems, nil
}

