// ErrScriptTimeout is returned when the script execution exceeds the allowed time.
var ErrScriptTimeout = errors.New("script execution timed out")

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Security & Performance Fix: Instantiate the VM once outside the loop.
	// Creating a VM is expensive; doing it inside the loop allows for easy Denial of Service via large inputs.
	vm := otto.New()

	// Security Fix: Enable the Interrupt channel.
	// This is required to stop the VM if the script enters an infinite loop.
	vm.Interrupt = make(chan func(), 1)

	// Performance Fix: Pre-compile the script.
	// Parsing the script string for every item is inefficient.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	var result []map[string]interface{}

	// Security Fix: Define a strict execution time limit per item.
	// Since filtering logic should be simple, 100ms is usually sufficient.
	const executionTimeLimit = 100 * time.Millisecond

	for _, item := range items {
		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Security Fix: Watchdog timer to prevent infinite loops.
		timer := time.AfterFunc(executionTimeLimit, func() {
			vm.Interrupt <- func() {
				panic("timeout")
			}
		})

		// Run the pre-compiled script
		value, err := vm.Run(script)

		// Stop the timer immediately if execution finishes successfully
		timer.Stop()

		if err != nil {
			// Check if the error was caused by our timeout interrupt
			if err.Error() == "timeout" {
				return nil, ErrScriptTimeout
			}
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
